// SPDX-License-Identifier: Apache-2.0
// Copyright Authors of Cilium

package quota

import (
	"context"
	"fmt"
	"sync"

	"github.com/sirupsen/logrus"

	cilium_v2 "github.com/cilium/cilium/pkg/k8s/apis/cilium.io/v2"
	"github.com/cilium/cilium/pkg/k8s/resource"
	"github.com/cilium/cilium/pkg/logging/logfields"
)

// PolicyQuotaController enforces per-namespace limits on the number of
// CiliumNetworkPolicy resources.
type PolicyQuotaController struct {
	log logrus.FieldLogger

	// policyCounts tracks the number of CiliumNetworkPolicy resources per namespace
	// protected by policyCountsMu
	policyCounts map[string]int
	policyCountsMu sync.RWMutex

	// maxPerNamespace is the maximum number of policies allowed per namespace.
	// A value of 0 means unlimited.
	maxPerNamespace int

	// ciliumNetworkPolicies is the resource for watching CiliumNetworkPolicy
	ciliumNetworkPolicies resource.Resource[*cilium_v2.CiliumNetworkPolicy]
}

// NewPolicyQuotaController creates a new PolicyQuotaController.
func NewPolicyQuotaController(
	log logrus.FieldLogger,
	ciliumNetworkPolicies resource.Resource[*cilium_v2.CiliumNetworkPolicy],
	maxPerNamespace int,
) *PolicyQuotaController {
	return &PolicyQuotaController{
		log:                   log,
		ciliumNetworkPolicies: ciliumNetworkPolicies,
		maxPerNamespace:       maxPerNamespace,
		policyCounts:          make(map[string]int),
	}
}

// Run implements the controller loop that watches CiliumNetworkPolicy resources
// and maintains per-namespace counts.
func (c *PolicyQuotaController) Run(ctx context.Context) {
	c.log.Info("Starting PolicyQuotaController")

	for {
		select {
		case <-ctx.Done():
			c.log.Info("Stopping PolicyQuotaController")
			return
		default:
		}

		events := c.ciliumNetworkPolicies.Events(ctx)
		for event := range events {
			switch event.Kind {
			case resource.Sync:
				c.log.Debug("CiliumNetworkPolicy resources synchronized")
				event.Done(nil)

			case resource.Upsert:
				c.onPolicyUpsert(event.Object)
				event.Done(nil)

			case resource.Delete:
				c.onPolicyDelete(event.Object)
				event.Done(nil)
			}
		}
	}
}

// onPolicyUpsert handles upsert events for CiliumNetworkPolicy resources.
func (c *PolicyQuotaController) onPolicyUpsert(policy *cilium_v2.CiliumNetworkPolicy) {
	namespace := policy.GetNamespace()
	if namespace == "" {
		return
	}

	c.policyCountsMu.Lock()
	defer c.policyCountsMu.Unlock()

	c.policyCounts[namespace]++
	c.log.WithFields(logrus.Fields{
		logfields.Namespace: namespace,
		"count":             c.policyCounts[namespace],
	}).Debug("Policy count incremented")
}

// onPolicyDelete handles delete events for CiliumNetworkPolicy resources.
func (c *PolicyQuotaController) onPolicyDelete(policy *cilium_v2.CiliumNetworkPolicy) {
	namespace := policy.GetNamespace()
	if namespace == "" {
		return
	}

	c.policyCountsMu.Lock()
	defer c.policyCountsMu.Unlock()

	if count, exists := c.policyCounts[namespace]; exists && count > 0 {
		c.policyCounts[namespace]--
	}
	c.log.WithFields(logrus.Fields{
		logfields.Namespace: namespace,
		"count":             c.policyCounts[namespace],
	}).Debug("Policy count decremented")
}

// CheckQuota checks if adding a new policy to the given namespace would exceed
// the quota. Returns an error if the quota would be exceeded.
func (c *PolicyQuotaController) CheckQuota(namespace string) error {
	if c.maxPerNamespace == 0 {
		// Unlimited quota
		return nil
	}

	c.policyCountsMu.RLock()
	count := c.policyCounts[namespace]
	c.policyCountsMu.RUnlock()

	if count >= c.maxPerNamespace {
		return fmt.Errorf(
			"policy quota exceeded in namespace %q: current count %d, max allowed %d",
			namespace, count, c.maxPerNamespace,
		)
	}

	return nil
}

// GetPolicyCount returns the current count of CiliumNetworkPolicy resources
// in the given namespace.
func (c *PolicyQuotaController) GetPolicyCount(namespace string) int {
	c.policyCountsMu.RLock()
	defer c.policyCountsMu.RUnlock()
	return c.policyCounts[namespace]
}

