func TestPolicyQuotaControllerCheckQuota(t *testing.T) {
	tests := []struct {
		name           string
		maxQuota       int
		currentCount   int
		expectedErr    bool
		expectedErrMsg string
	}{
		{
			name:         "unlimited quota",
			maxQuota:     0,
			currentCount: 100,
			expectedErr:  false,
		},
		{
			name:        "quota not exceeded",
			maxQuota:    10,
			currentCount: 5,
			expectedErr: false,
		},
		{
			name:           "quota exceeded",
			maxQuota:       10,
			currentCount:   10,
			expectedErr:    true,
			expectedErrMsg: "policy quota exceeded",
		},
		{
			name:           "quota at limit",
			maxQuota:       1,
			currentCount:   1,
			expectedErr:    true,
			expectedErrMsg: "policy quota exceeded",
		},
	}

	for _, tt := range tests {
