		t.Errorf("After upsert in other namespace, test-ns count = %d, expected 2", count)
	}
	if count := controller.GetPolicyCount("other-ns"); count != 1 {
		t.Errorf("After upsert in other namespace, other-ns count = %d, expected 1", count)
	}
}

func TestPolicyQuotaControllerOnPolicyDelete(t *testing.T) {
	log := logrus.New().WithField("test", "OnPolicyDelete")
	mockRes := &mockResource{
		events: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy]),
	}

	controller := NewPolicyQuotaController(log, mockRes, 10)

	policy := &cilium_v2.CiliumNetworkPolicy{}
	policy.Namespace = "test-ns"
