	controller.onPolicyDelete(policy)
	if count := controller.GetPolicyCount("test-ns"); count != 0 {
		t.Errorf("After delete from empty namespace, GetPolicyCount() = %d, expected 0", count)
	}
}

func TestPolicyQuotaControllerNewPolicyQuotaController(t *testing.T) {
	log := logrus.New()
	mockRes := &mockResource{
		events: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy]),
	}

	controller := NewPolicyQuotaController(log, mockRes, 5)

